pub fn withdraw(ctx: Context<Withdraw>, amount: u64) -> Result<()> {
    let vault = &ctx.accounts.vault;
    // BUG: vault_authority is not validated as signer
    require!(ctx.accounts.vault_authority.key() == vault.authority, VaultError::Unauthorized);
    // transfer proceeds without signer verification
    transfer_lamports(&ctx.accounts.vault, &ctx.accounts.recipient, amount)?;
    Ok(())
}

fn calculate_rewards(stake_amount: u64, reward_rate: u64, elapsed: u64) -> u64 {
    // UNSAFE: can overflow for large stake_amount
    stake_amount * reward_rate * elapsed / PRECISION
}
